import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const p=JSON.parse('{"title":"What is wikimem?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is-wikimem.md","filePath":"guide/what-is-wikimem.md","lastUpdated":1784858676000}'),n={name:"guide/what-is-wikimem.md"};function r(s,e,d,l,h,c){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="what-is-wikimem" tabindex="-1">What is wikimem? <a class="header-anchor" href="#what-is-wikimem" aria-label="Permalink to &quot;What is wikimem?&quot;">​</a></h1><p>wikimem is a <strong>file-first memory pipeline</strong> for AI agents: long-term memory stored as <strong>plain markdown files</strong> (one file per category, one <code>##</code> heading per item), searched by an <strong>in-memory BM25 index</strong>, and connected by <strong>wiki-links</strong> — <code>[[category:item]]</code> references that recall meaning-related items keyword search cannot reach.</p><p>It is a Python library with <strong>zero mandatory dependencies</strong>. <code>pip install wikimem</code> gives you the complete system: storage, retrieval (including Chinese, via character bigrams), wiki-link expansion, and an append-only journal.</p><h2 id="the-problem-it-solves" tabindex="-1">The problem it solves <a class="header-anchor" href="#the-problem-it-solves" aria-label="Permalink to &quot;The problem it solves&quot;">​</a></h2><p>&quot;Agent memory&quot; usually arrives as infrastructure: a vector database for similarity, an embedding endpoint you now depend on, sometimes a graph database for relations, and docker-compose to hold it all together. For a personal agent — thousands of items, not billions — that stack is upside down: the infrastructure outweighs the data, the data is unreadable without tooling, and every layer is a new way to lose memories.</p><p>wikimem inverts it. The memory <strong>is</strong> a folder of markdown files. Everything else — the BM25 index, the optional vector cache — is derived state that can be deleted and rebuilt from those files at any time. The design predecessor of this project ran mem0 + Qdrant + Neo4j to do what this library does with a text folder; the association recall the graph database was there to provide, wiki-links deliver with a mechanical one-hop expansion.</p><h2 id="the-four-design-rules" tabindex="-1">The four design rules <a class="header-anchor" href="#the-four-design-rules" aria-label="Permalink to &quot;The four design rules&quot;">​</a></h2><p>Everything in the library follows from these (fixed in XnneHangLab ADR-0001):</p><ol><li><strong>Markdown files are the only source of truth.</strong> One file per category under <code>category/</code> (<code>memory/category/preferences.md</code>), one <code>##</code> heading per item; diary events live as per-day files under <code>diary/</code>. Read them, edit them, diff them — your editor is the admin UI.</li><li><strong>No unreadable truth on disk.</strong> Every derived artifact (indexes, vector caches) is deletable and rebuildable from the files. The BM25 index lives in memory, built at startup, never persisted.</li><li><strong>Never block the conversation.</strong> Retrieval is synchronous, token-budgeted, and fail-open, with <strong>zero LLM calls</strong>; memorization is asynchronous and costs the host at most <strong>one</strong> LLM call per turn.</li><li><strong>What happened is always answerable.</strong> Every mutation appends one line to <code>journal.jsonl</code>; retrieval can explain its scoring.</li></ol><h2 id="one-pipeline-no-modes" tabindex="-1">One pipeline, no modes <a class="header-anchor" href="#one-pipeline-no-modes" aria-label="Permalink to &quot;One pipeline, no modes&quot;">​</a></h2><p>There are no configuration modes to choose between. wikimem is one pipeline; optional extras unlock enhancements that activate automatically and never conflict:</p><table tabindex="0"><thead><tr><th>Install</th><th>Adds</th><th>Use case</th></tr></thead><tbody><tr><td><code>wikimem</code></td><td>nothing — zero dependencies</td><td>Always fully works: storage, BM25 retrieval (Chinese via char-bigrams), wiki-links, journal</td></tr><tr><td><code>wikimem[zh]</code></td><td>jieba</td><td>Sharper Chinese keyword recall than bigrams — picked up automatically once installed, nothing to configure</td></tr><tr><td><code>wikimem[embed]</code></td><td>httpx + numpy</td><td>Semantic recall (match by meaning, not wording) — only active when you pass an <code>embedder</code>; endpoint down → BM25 carries on</td></tr><tr><td><code>wikimem[all]</code></td><td>both of the above</td><td>The &quot;don&#39;t make me think&quot; option</td></tr></tbody></table><p>Installing every extra changes nothing until you actually use it: jieba is picked up by the tokenizer when importable, and the embedding path only runs when you construct <code>MemoryIndex</code> with an <code>embedder</code>.</p><h2 id="what-wikimem-is-not" tabindex="-1">What wikimem is not <a class="header-anchor" href="#what-wikimem-is-not" aria-label="Permalink to &quot;What wikimem is not&quot;">​</a></h2><ul><li><strong>Not a vector database.</strong> There is an optional vector <em>cache</em>, but it is derived state — deletable, rebuildable, never the source of truth.</li><li><strong>Not a graph database.</strong> The &quot;graph&quot; is text: wiki-links inside item content. Expansion is an exact-name lookup, not a traversal engine.</li><li><strong>Not a note-taking app.</strong> The format is deliberately Obsidian-<em>adjacent</em> (markdown + <code>[[...]]</code>), but the unit is a few-sentence <strong>item</strong>, not a document, and the writer is usually an extraction LLM, not a person.</li><li><strong>Not an agent framework.</strong> wikimem has no opinion about your LLM, your prompt, or your event loop. The host wires it in — see <a href="/guide/host-integration.html">Host Integration</a>.</li></ul><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Pre-alpha (<code>0.1.0.dev0</code>), built milestone by milestone against XnneHangLab ADR-0001:</p><ul><li><strong>M1 ✅ — storage</strong>: category files, item model + provenance metadata, wiki-link parsing, <code>journal.jsonl</code>, atomic writes</li><li><strong>M2 ✅ — retrieval</strong>: in-memory BM25 (char-bigram fallback, <code>[zh]</code> extra for jieba), one-hop wiki-link expansion, token budget, explain</li><li><strong>M3 ✅ — embedding fusion</strong> (<code>[embed]</code> extra): content-hash vector cache (versioned <code>.npy</code> + plain-text keys), memmap tiers with binary quantization above 10k items, pluggable <code>VectorIndex</code> port, silent BM25 fallback</li><li><strong>M4 — CLI</strong> (next): <code>ls / show / grep / explain / graph</code></li></ul><h2 id="license-and-credits" tabindex="-1">License and credits <a class="header-anchor" href="#license-and-credits" aria-label="Permalink to &quot;License and credits&quot;">​</a></h2><p>Apache-2.0. The extraction-prompt design borrows from <a href="https://github.com/NevaMind-AI/memU" target="_blank" rel="noreferrer">memU</a> (Apache-2.0) — adopted as design inspiration, not as a dependency (lab ADR-0002). The BM25 + cosine fusion formula follows what memU&#39;s ADR-0007 converged on.</p>',20)])])}const u=t(n,[["render",r]]);export{p as __pageData,u as default};
